import { NextResponse } from "next/server"

export async function GET() {
  // Generate sample time series data
  const now = Date.now()
  const timeSeriesData = Array.from({ length: 24 }, (_, i) => ({
    time: new Date(now - (23 - i) * 60 * 60 * 1000).toLocaleTimeString(),
    inferred_watts: Math.floor(Math.random() * 500 + 100),
  }))

  return NextResponse.json({
    timeSeriesData,
    cpuPowerCorrelation: Array.from({ length: 24 }, (_, i) => ({
      time: new Date(now - (23 - i) * 60 * 60 * 1000).toLocaleTimeString(),
      cpu_percent: Math.floor(Math.random() * 100),
      inferred_watts: Math.floor(Math.random() * 500 + 100),
    })),
    computerStats: [
      { computer_name: "LAB-PC-01", avgWatts: 250, maxWatts: 350 },
      { computer_name: "LAB-PC-02", avgWatts: 180, maxWatts: 280 },
      { computer_name: "LAB-PC-03", avgWatts: 200, maxWatts: 300 },
      { computer_name: "LAB-PC-04", avgWatts: 150, maxWatts: 220 },
      { computer_name: "SERVER-01", avgWatts: 450, maxWatts: 600 },
    ],
    idleAnalysis: [
      { computer_name: "LAB-PC-02", idleHours: 8, estimatedWastedWatts: 120 },
      { computer_name: "LAB-PC-04", idleHours: 12, estimatedWastedWatts: 180 },
    ],
  })
}
